import { GoogleGenAI } from "@google/genai";

export async function generateJustification(industry: string, scale: string): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    You are a pricing strategy expert. Explain why a SaaS tool like "NexusFlow" (an AI-powered workspace orchestrator) 
    with a Professional tier of $29/user/month is justified for a company in the ${industry} industry with a ${scale} scale.
    Keep the explanation professional, persuasive, and under 150 words. Focus on ROI, productivity gains, and competitive advantage.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Unable to generate justification at this time.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Our pricing is justified through the immense productivity gains and infrastructure cost savings NexusFlow provides to modern teams.";
  }
}

