const PricingCalculator = () => {
  const [users, setUsers] = useState(10);
  const [isAnnual, setIsAnnual] = useState(true);
  const [addOns, setAddOns] = useState({
    api: false,
    security: false
  });

  const basePrice = 29;
  const annualDiscount = 0.8; // 20% off

  const totalPrice = useMemo(() => {
    let pricePerUser = basePrice;
    if (isAnnual) pricePerUser *= annualDiscount;

    let subtotal = pricePerUser * users;
    if (addOns.api) subtotal += 49;
    if (addOns.security) subtotal += 99;

    return subtotal.toFixed(2);
  }, [users, isAnnual, addOns]);

  return (
    <section id="calculator" className="py-24 bg-indigo-50/50">
      <div className="max-w-5xl mx-auto px-6">
        <div className="bg-white rounded-3xl p-8 lg:p-12 shadow-2xl border border-indigo-100 flex flex-col lg:flex-row gap-12">
          <div className="flex-1">
            <h2 className="text-3xl font-bold text-slate-900 mb-2">Price Calculator</h2>
            <p className="text-slate-500 mb-10">Estimate your investment based on your team's specific requirements.</p>

            <div className="space-y-10">
              {/* User Count Slider */}
              <div>
                <div className="flex justify-between items-center mb-4">
                  <label className="text-slate-700 font-semibold flex items-center gap-2">
                    <Users className="w-4 h-4 text-indigo-500" /> Team Size
                  </label>
                  <span className="text-indigo-600 font-bold bg-indigo-50 px-3 py-1 rounded-lg">{users} users</span>
                </div>
                <input 
                  type="range" 
                  min="1" 
                  max="100" 
                  value={users} 
                  onChange={(e) => setUsers(parseInt(e.target.value))}
                  className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-indigo-600"
                />
              </div>

              {/* Billing Toggle */}
              <div className="flex items-center justify-between">
                <div>
                  <h4 className="font-semibold text-slate-900">Billing Cycle</h4>
                  <p className="text-xs text-slate-500">Save 20% with annual billing</p>
                </div>
                <div className="flex items-center gap-4">
                  <span className={`text-sm ${!isAnnual ? 'text-indigo-600 font-bold' : 'text-slate-400'}`}>Monthly</span>
                  <button 
                    onClick={() => setIsAnnual(!isAnnual)}
                    className="relative w-14 h-8 bg-slate-200 rounded-full transition-colors"
                  >
                    <div className={`absolute top-1 left-1 w-6 h-6 bg-white rounded-full shadow-md transition-transform duration-300 ${isAnnual ? 'translate-x-6 bg-indigo-600' : ''}`}></div>
                  </button>
                  <span className={`text-sm ${isAnnual ? 'text-indigo-600 font-bold' : 'text-slate-400'}`}>Yearly</span>
                </div>
              </div>

              {/* Add-ons */}
              <div>
                <h4 className="font-semibold text-slate-900 mb-4">Add-ons</h4>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  <button 
                    onClick={() => setAddOns(prev => ({ ...prev, api: !prev.api }))}
                    className={`p-4 rounded-xl border text-left transition-all ${
                      addOns.api ? 'border-indigo-600 bg-indigo-50' : 'border-slate-200 bg-white hover:border-slate-300'
                    }`}
                  >
                    <div className="flex justify-between items-center mb-1">
                      <span className="font-bold text-sm">Advanced API</span>
                      <div className={`w-4 h-4 rounded border flex items-center justify-center ${addOns.api ? 'bg-indigo-600 border-indigo-600' : 'border-slate-300'}`}>
                        {addOns.api && <Check className="text-white w-3 h-3" />}
                      </div>
                    </div>
                    <p className="text-xs text-slate-500">+$49/mo flat</p>
                  </button>
                  <button 
                    onClick={() => setAddOns(prev => ({ ...prev, security: !prev.security }))}
                    className={`p-4 rounded-xl border text-left transition-all ${
                      addOns.security ? 'border-indigo-600 bg-indigo-50' : 'border-slate-200 bg-white hover:border-slate-300'
                    }`}
                  >
                    <div className="flex justify-between items-center mb-1">
                      <span className="font-bold text-sm">Enterprise Security</span>
                      <div className={`w-4 h-4 rounded border flex items-center justify-center ${addOns.security ? 'bg-indigo-600 border-indigo-600' : 'border-slate-300'}`}>
                        {addOns.security && <Check className="text-white w-3 h-3" />}
                      </div>
                    </div>
                    <p className="text-xs text-slate-500">+$99/mo flat</p>
                  </button>
                </div>
              </div>
            </div>
          </div>

          <div className="lg:w-1/3 bg-slate-900 rounded-2xl p-8 text-white flex flex-col justify-between">
            <div>
              <h4 className="text-slate-400 font-medium mb-2 uppercase text-xs tracking-widest">Estimated Total</h4>
