import { GoogleGenAI } from "@google/genai";

export async function generateJustification(industry: string, scale: string): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    You are a high-level SaaS Pricing Consultant. Explain why a modern AI workspace tool like "NexusFlow" 
    with a Professional tier of $49/user/month is a fair and high-value investment for a company in the ${industry} 
    at a ${scale} scale. 
    Focus on specific business outcomes like reduced operational drag, higher employee satisfaction, and competitive agility.
    Output a single, concise, persuasive paragraph (max 100 words).
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "NexusFlow provides unparalleled value through automated workflows and context-aware intelligence.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Our pricing is justified by the significant reduction in context-switching and the 30% average increase in team output recorded by our users.";
  }
}

