                   <div className="w-full flex justify-center"><div className="w-10 h-10 border-4 border-amber-500 border-t-transparent rounded-full animate-spin"></div></div>
                 ) : (
                   <p className="text-2xl font-serif italic leading-relaxed text-slate-700">"{justification}"</p>
                 )}
               </div>
               <div className="mt-12 flex flex-col sm:flex-row gap-4">
                  <div className="flex-1 space-y-2">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Target Audience</label>
                    <select 
                      value={industry} onChange={(e) => setIndustry(e.target.value)}
                      className="w-full bg-slate-100 border-none rounded-xl px-4 py-3 text-sm font-bold outline-none focus:ring-2 ring-amber-500"
                    >
                      {['Digital Nomad', 'Tech Exec', 'Eco-Conscious Parent', 'Creative Studio'].map(i => <option key={i} value={i}>{i}</option>)}
                    </select>
                  </div>
                  <button onClick={fetchJustification} className="sm:self-end bg-slate-900 text-white px-8 py-3 rounded-xl text-sm font-black uppercase hover:bg-amber-600 transition-colors">Re-evaluate</button>
               </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

